    12→  
    13→  /** program for this interpeter, initialized in constructors. */
    14→  AST prog;
    15→  
    16→  /** Constructor for a program given in a file. Not used in Assignment 2*/
    17→  public Interpreter(String fileName) throws IOException { 
    18→    Parser p = new Parser(fileName);
    19→    prog = p.parse();
    20→  }
    21→  
    22→  /** Constructor for a program already embedded in a Parser object. */
    23→  public Interpreter(Parser p) { 
    24→    prog = p.parse();
    25→  }  
    26→  
    27→  /** Constructor for a program embedded in a Reader. Not used in Assignment 2. */
    28→  public Interpreter(Reader reader) { 
    29→    Parser p = new Parser(reader);
    30→    prog = p.parse();
    31→  }
    32→  
    33→  /** Parses and CBV interprets the input embeded in parser */
    34→  public JamVal callByValue() { return prog.accept(valueEvalVisitor); }
    35→  
