   189→  /** Parses <id-list> where
   190→    *   <id-list>       ::= <empty> | <prop-id-list>
   191→    *   <prop-id-list>  ::= <id> | <id> , <id-list> 
   192→    *  NOTE: consumes `to' following <id-list>
   193→    */
   194→  private Variable[] parseVars() {
   195→ 
   196→    LinkedList<Variable> vars = new LinkedList<Variable>();
   197→    Token t = in.readToken();
   198→    if (t == Lexer.TO) return new Variable[0];
   199→    
   200→    do {
   201→      if (! (t instanceof Variable)) error(t, "variable");
   202→      vars.addLast((Variable)t);
   203→      t = in.readToken();
   204→      if (t == Lexer.TO) break; 
   205→      if (t != Comma.ONLY) error(t, "'to' or ',' ");
   206→      // Comma found, read next variable
   207→      t = in.readToken();
   208→    } while (true);
   209→    return (Variable[]) vars.toArray(new Variable[0]);
   210→  }
   211→  
   212→  /** Parses a proper list of definitions, more technically parses
   213→    *   <prop-def-list> ::= <def> | <def> <def-list> 
   214→    *   NOTE: consumes `in' following <prop-def-list> */
