   223→        throw new ParseException("right hand side of definition `" + d + "' is not a map expression");
   224→      defs.addLast(d);
   225→      t = in.readToken();
   226→    } while (t != Lexer.IN);
   227→    
   228→    return (Def[]) defs.toArray(new Def[0]);
   229→  }
