   234→    */
   235→  private Def parseDef(Token var) {
   236→    
   237→    if (! (var instanceof Variable)) error(var, "variable");
   238→    
   239→    Token key = in.readToken();
   240→    if (key != Lexer.BIND) error (key,"`:='");
   241→    
   242→    AST exp = parseExp();
   243→    
   244→    Token semi = in.readToken();
   245→    if (semi != SemiColon.ONLY) error(semi,"`;'");
   246→    return new Def((Variable) var, exp);
   247→  }
